fn gather_ts(dir: &Path, out: &mut Vec<PathBuf>) -> Result<(), String> {
    let entries = fs::read_dir(dir).map_err(|e| format!("scan {}: {e}", dir.display()))?;
    for item in entries {
        let path = item.map_err(|e| format!("scan {}: {e}", dir.display()))?.path();
