use crate::model::{Observation, State};

pub fn mote_e(a: &mut State, b: &str, c: bool) -> Observation {
    // Find the definition that would be visible *now* after preceding edits.
    // Restrict to currently-active slot roots and pick the newest entry.
    let mut best = None;
    for entry in &a.entries {
        if entry.symbol != b {
            continue;
        }
        let Some(root) = a.active.get(&entry.slot) else {
            continue;
        };
        if !entry.path.starts_with(root) {
            continue;
        }
        let replace = match &best {
            None => true,
            Some(prev) => (entry.epoch, &entry.path, entry.line) > (prev.epoch, &prev.path, prev.line),
        };
        if replace {
            best = Some(entry.clone());
        }
    }

    if let Some(entry) = best {
        let reused = a
            .last_seen
            .get(b)
            .map(|old| *old == entry.handle)
            .unwrap_or(false);
        a.last_seen.insert(b.to_string(), entry.handle);
        Observation {
            label: String::new(),
            symbol: b.to_string(),
            found: true,
            path: entry.path,
            source: entry.source,
            line: entry.line,
            // Epoch is the harness epoch at query time.
            epoch: a.epoch,
            reused,
            // By construction this is the visible, current definition.
            fresh: true,
        }
    } else {
        // For queries (c=true) this is stale; for misses (c=false) this is fresh.
        Observation::missing("", b, a.epoch, !c)
    }
}
EOF
