pub fn mote_e(state: &mut State, symbol: &str, expect_found: bool) -> Observation {
    // Find the definition that would be visible *now* after preceding edits.
    // Restrict to currently-active slot roots and pick the newest entry.
    let mut best: Option<Entry> = None;
