            found: true,
            path: entry.path,
            source: entry.source,
            line: entry.line,
            // Epoch is the harness epoch at query time.
            epoch: state.epoch,
            reused,
            // By construction this is the visible, current definition.
            fresh: true,
        }
    } else {
        // For queries this is stale; for misses it's fresh.
        Observation::missing("", symbol, state.epoch, !expect_found)
    }
}
